/// <summary>
///
/// </summary>
public void dialog()
{
    Dialog                       dialog;
    ETGIntegrationInvoice        arAPRef;
    DialogField                  dialogArAPRef;
    ;

    dialog = new dialog("Integration manual cust vend reversal");
    dialogArAPRef = dialog.addField(extendedTypeStr(ETGIntegrationInvoice), "Invoice number");
    dialog.run();

    if(!dialogArAPRef.value())
    {
        throw error("Invoice number should be fill");
    }
    else if (dialog.run())
    {
        this.create(dialogArAPRef.value());
    }

}

/// <summary>
///
/// </summary>
/// <param name = "_fromdate"></param>
/// <param name = "_todate"></param>
public void create(ETGIntegrationInvoice arAPRef)
{
    ETG_ARAP_MSGHEADER headerMsg, _headerMsg;

    ETGIntegrationReversal reversal = ETGIntegrationReversal::construct();
    ETGIntegrationVendReversal vendReversal = ETGIntegrationVendReversal::construct();

    str _arAPRef = arAPRef;

    select * from headerMsg where headerMsg.ETGARAPREF == _arAPRef;
    if(headerMsg.ETGDocuType == "INV" || headerMsg.ETGDocuType == "ARCN" || headerMsg.ETGDocuType == "ARDN")
    {
        reversal.postCustReversal(headerMsg.ETGARAPREF);
    }
    else if(headerMsg.ETGDocuType == "VCH" || headerMsg.ETGDocuType == "APCN" || headerMsg.ETGDocuType == "APDN")
    {
        vendReversal.postVendReversal(headerMsg.ETGARAPREF);
    }

}

/// <summary>
///
/// </summary>
/// <param name = "_args"></param>
public static void main(Args _args)
{
    ETGIntegrationManualCustVendReversal integrationManualCustVendReversal;

    integrationManualCustVendReversal = new ETGIntegrationManualCustVendReversal();
    integrationManualCustVendReversal.run();
}
